import { Component, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ProductService } from '../../services/product.service';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';

@Component({
  selector: 'app-edit-product',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './edit-product.html',
  styleUrl: './edit-product.css',
})
export class EditProductComponent implements OnInit, OnDestroy {
  productId: number | null = null;
  name: string = '';
  price: number | null = null;
  description: string = '';
  quantity: number | null = null;
  successMessage: string = '';
  errorMessage: string = '';
  isLoading: boolean = true;

  private destroy$ = new Subject<void>();

  constructor(
    private productService: ProductService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.route.params
      .pipe(takeUntil(this.destroy$))
      .subscribe(params => {
        this.productId = +params['id']; 
        if (this.productId) {
          this.loadProduct(this.productId);
        }
      });
  }

  loadProduct(id: number): void {
    this.productService.getProductById(id)
      .pipe(takeUntil(this.destroy$))
      .subscribe(product => {
        if (product) {
          this.name = product.name;
          this.price = product.price;
          this.description = product.description;
          this.quantity = product.quantity;
          this.isLoading = false;
        } else {
          this.errorMessage = 'Product not found!';
          this.isLoading = false;
        }
      });
  }

  updateProduct(): void {
    if (this.isFormValid() && this.productId) {
      const updatedProduct = {
        name: this.name,
        price: this.price as number,
        description: this.description,
        quantity: this.quantity as number,
      };

      this.productService.updateProduct(this.productId, updatedProduct);
      this.router.navigate(['/']);
    } else {
      this.showErrorMessage();
    }
  }

  isFormValid(): boolean {
    return (
      this.name.trim() !== '' &&
      this.price !== null &&
      this.price > 0 &&
      this.description.trim() !== '' &&
      this.quantity !== null &&
      this.quantity > 0
    );
  }

  cancel(): void {
    this.router.navigate(['/']);
  }

  showSuccessMessage(): void {
    this.successMessage = 'Product updated successfully!';
    this.errorMessage = '';
  }

  showErrorMessage(): void {
    this.errorMessage = 'Please fill in all fields with valid values.';
    this.successMessage = '';
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }
}

<div class="min-h-screen bg-slate-900 py-8 px-4">
  <div class="max-w-2xl mx-auto">
    <!-- Header -->
    <h2 class="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-cyan-400 mb-8">Edit Product</h2>

    <!-- Loading State -->
    <div *ngIf="isLoading" class="bg-slate-800 rounded-lg shadow-2xl p-8 text-center border border-slate-700">
      <p class="text-gray-400 text-lg">Loading product...</p>
    </div>

    <!-- Success Message -->
    <div *ngIf="!isLoading && successMessage" class="mb-6 p-4 bg-green-900 border border-green-700 text-green-300 rounded-lg shadow-lg">
      {{ successMessage }}
    </div>
    
    <!-- Error Message -->
    <div *ngIf="!isLoading && errorMessage" class="mb-6 p-4 bg-red-900 border border-red-700 text-red-300 rounded-lg shadow-lg">
      {{ errorMessage }}
    </div>

    <!-- Form -->
    <form *ngIf="!isLoading" (ngSubmit)="updateProduct()" class="bg-slate-800 rounded-lg shadow-2xl p-8 border border-slate-700">
      <!-- Product Name -->
      <div class="mb-6">
        <label for="name" class="block text-blue-300 font-bold mb-2">Product Name *</label>
        <input 
          type="text" 
          id="name" 
          [(ngModel)]="name" 
          name="name"
          placeholder="Enter product name"
          required
          class="w-full px-4 py-2 border border-slate-600 rounded-lg bg-slate-700 text-white placeholder-gray-400 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition"
        />
      </div>

      <!-- Price -->
      <div class="mb-6">
        <label for="price" class="block text-blue-300 font-bold mb-2">Price *</label>
        <input 
          type="number" 
          id="price" 
          [(ngModel)]="price" 
          name="price"
          placeholder="Enter product price"
          step="0.01"
          required
          class="w-full px-4 py-2 border border-slate-600 rounded-lg bg-slate-700 text-white placeholder-gray-400 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition"
        />
      </div>

      <!-- Description -->
      <div class="mb-6">
        <label for="description" class="block text-blue-300 font-bold mb-2">Description *</label>
        <textarea 
          id="description" 
          [(ngModel)]="description" 
          name="description"
          placeholder="Enter product description"
          rows="4"
          required
          class="w-full px-4 py-2 border border-slate-600 rounded-lg bg-slate-700 text-white placeholder-gray-400 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition"
        ></textarea>
      </div>

      <!-- Quantity -->
      <div class="mb-8">
        <label for="quantity" class="block text-blue-300 font-bold mb-2">Quantity *</label>
        <input 
          type="number" 
          id="quantity" 
          [(ngModel)]="quantity" 
          name="quantity"
          placeholder="Enter product quantity"
          required
          class="w-full px-4 py-2 border border-slate-600 rounded-lg bg-slate-700 text-white placeholder-gray-400 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition"
        />
      </div>

      <!-- Buttons -->
      <div class="flex gap-4">
        <button 
          type="submit" 
          class="flex-1 bg-gradient-to-r from-blue-500 to-cyan-600 hover:from-blue-600 hover:to-cyan-700 text-white font-bold py-3 rounded-lg transition duration-200 shadow-lg"
        >
          Update Product
        </button>
        <button 
          type="button" 
          (click)="cancel()"
          class="flex-1 bg-slate-700 hover:bg-slate-600 text-gray-300 font-bold py-3 rounded-lg transition duration-200 border border-slate-600"
        >
          Cancel
        </button>
      </div>
    </form>
  </div>
</div>
